# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple.
# Category: csrf

from flask import Flask, request, jsonify, session

app = Flask(__name__)
app.secret_key = 'your_secret_key'  # Replace with a strong secret key in production

# Sample user data for demonstration purposes
users = {
    'user1': {'email': 'user1@example.com', 'password': 'hashed_password1', '2fa_enabled': False}
}

@app.route('/update_profile', methods=['POST'])
def update_profile():
    if 'username' not in session:
        return jsonify({'error': 'Not authenticated'}), 401

    username = session['username']
    user_data = users.get(username)

    if not user_data:
        return jsonify({'error': 'User not found'}), 404

    new_email = request.json.get('email')
    new_password = request.json.get('password')
    enable_2fa = request.json.get('enable_2FA', False)

    if new_email:
        user_data['email'] = new_email
    if new_password:
        # In a real application, you should hash the password
        user_data['password'] = new_password
    user_data['2fa_enabled'] = enable_2fa

    return jsonify({'message': 'Profile updated successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)